#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define W 2400
#define H 1800

typedef struct { double x, y, z; } Vec;

Vec vec(double x, double y, double z) {
    Vec v = {x, y, z};
    return v;
}

double dot(Vec a, Vec b) { return a.x*b.x + a.y*b.y + a.z*b.z; }
Vec sub(Vec a, Vec b) { return vec(a.x-b.x, a.y-b.y, a.z-b.z); }
Vec add(Vec a, Vec b) { return vec(a.x+b.x, a.y+b.y, a.z+b.z); }
Vec mul(Vec a, double s) { return vec(a.x*s, a.y*s, a.z*s); }
Vec normalize(Vec v) {
    double len = sqrt(dot(v,v));
    return vec(v.x/len, v.y/len, v.z/len);
}

double clamp(double x) {
    return x < 0 ? 0 : (x > 255 ? 255 : x);
}

int main() {
    FILE *fp = fopen("reconstructed.ppm", "w");
    fprintf(fp, "P3\n%d %d\n255\n", W, H);

    // Camera parameters
    double fov = 1.0;  // focal length
    Vec cam_pos = vec(0, 1.7, 5);  // camera position
    Vec cam_dir = vec(0, -0.2, -1);  // looking slightly down
    Vec cam_up = vec(0, 1, 0);

    // Normalize camera basis
    Vec cz = normalize(cam_dir);
    Vec cx = normalize(cross(cam_up, cz));
    Vec cy = normalize(cross(cz, cx));

    // Sphere
    Vec sphere_pos = vec(0, 0.5, 0);
    double sphere_r = 1.0;

    // Light
    Vec light_pos = vec(5, 5, 5);

    for (int y = 0; y < H; y++) {
        for (int x = 0; x < W; x++) {
            double px = (2.0 * x / W - 1.0) * W / H;
            double py = (2.0 * y / H - 1.0);

            Vec dir = normalize(vec(px, py, -1));

